using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

var notes = new NoteService();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(notes.AddNote),
    AIFunctionFactory.Create(notes.GetNotes),
};

IChatClient client = new ChatClientBuilder(
        new OpenAIChatClient(new OpenAIClient(apiKey), modelId))
    .UseFunctionInvocation()
    .Build();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to research the given topic thoroughly.

        Follow this workflow:
        1. Search the web for information about the topic using multiple varied queries.
        2. Take notes on the key findings using the note-taking tool.
        3. After gathering enough information, review your notes and produce a final summary.

        Always search at least 3 different queries to get broad coverage.
        Take notes as you go so you don't lose information.
        End with a comprehensive summary of your findings.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}"),
};

var response = await client.GetResponseAsync(messages, new ChatOptions { Tools = tools });

Console.WriteLine("\n===== RESEARCH SUMMARY =====\n");
Console.WriteLine(response.Text);

if (notes.AllNotes.Count > 0)
{
    Console.WriteLine("\n===== RESEARCH NOTES =====\n");
    for (int i = 0; i < notes.AllNotes.Count; i++)
        Console.WriteLine($"  {i + 1}. {notes.AllNotes[i]}");
}

// --- Tool Definitions ---

[Description("Searches the web for the given query and returns a list of result snippets.")]
static async Task<string> SearchWeb([Description("The search query")] string query)
{
    Console.WriteLine($"  🔍 Searching: \"{query}\"");
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    try
    {
        var encoded = Uri.EscapeDataString(query);
        var html = await http.GetStringAsync($"https://html.duckduckgo.com/html/?q={encoded}");

        var snippets = new List<string>();
        var marker = "result__snippet";
        var pos = 0;
        while (snippets.Count < 6 && (pos = html.IndexOf(marker, pos, StringComparison.Ordinal)) >= 0)
        {
            var start = html.IndexOf('>', pos) + 1;
            var end = html.IndexOf('<', start);
            if (start > 0 && end > start)
            {
                var snippet = System.Net.WebUtility.HtmlDecode(html[start..end].Trim());
                if (!string.IsNullOrWhiteSpace(snippet))
                    snippets.Add(snippet);
            }
            pos = end > 0 ? end : pos + 1;
        }

        return snippets.Count > 0
            ? string.Join("\n\n", snippets.Select((s, i) => $"[{i + 1}] {s}"))
            : "No results found. Try a different query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

// --- Note Service ---

sealed class NoteService
{
    public List<string> AllNotes { get; } = [];

    [Description("Saves a research note for later review. Use this to record important findings.")]
    public string AddNote([Description("The content of the note to save")] string note)
    {
        AllNotes.Add(note);
        Console.WriteLine($"  📝 Note added ({AllNotes.Count} total)");
        return $"Note saved. You now have {AllNotes.Count} note(s).";
    }

    [Description("Retrieves all notes taken so far. Use before writing the final summary.")]
    public string GetNotes()
    {
        if (AllNotes.Count == 0)
            return "No notes taken yet.";

        return string.Join("\n", AllNotes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

